const payload = $json.body || $json;
const event = String(payload.event || payload.type || '').toLowerCase();
if (event && !event.includes('messages')) return [];

const data = payload.data || payload;
const key = data.key || {};
const remoteJid = String(key.remoteJid || '');

// Ignora mensagens próprias e grupos
if (!remoteJid || remoteJid.endsWith('@g.us') || key.fromMe) return [];

// Extrai número (dígitos para lookup)
const phone = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');

// Extrai texto ou metadados de áudio (vários formatos Evolution API)
const msg = data.message || {};
const audio = msg.audioMessage || msg.pttMessage || {};
const messageId = String(key.id || data.id || '').trim();
const text = (
  msg.conversation ||
  msg.extendedTextMessage?.text ||
  msg.imageMessage?.caption ||
  msg.videoMessage?.caption ||
  audio.caption ||
  audio.transcription ||
  audio.text ||
  data.transcription ||
  ''
).trim();

const audioUrl = String(audio.url || audio.mediaUrl || audio.media_url || data.mediaUrl || data.audioUrl || data.url || '').trim();
const audioBase64 = String(audio.base64 || data.base64 || data.audioBase64 || '').trim();
const mimeType = String(audio.mimetype || audio.mimeType || data.mimetype || data.mimeType || 'audio/ogg');
const hasAudio = Boolean(audioUrl || audioBase64 || (messageId && (msg.audioMessage || msg.pttMessage)));

// Ignora mensagens sem texto e sem áudio (figurinhas, imagens sem legenda, etc.)
if (!text && !hasAudio) return [];

return [{ json: { phone, message: text, remoteJid, audioUrl, audioBase64, mimeType, messageId, evolutionInstance: data.instance || payload.instance, rawEvolutionData: payload, isAudio: Boolean(!text && hasAudio) } }];

// Se o Horizonte já enviou pela Evolution, não duplicar.
const backendResp = $json;
const extractedItem = $('Extrair telefone e mensagem').first();
const phone = extractedItem?.json?.phone || '';

if (backendResp?.whatsappOutboundSent) return [];

const textToSend = String(backendResp?.reply || '').trim();
if (!textToSend || !phone) return [];

return [{ json: { phone, reply: textToSend } }];
